external_knowledge:
- "golden goose" refers to the sales channel that generates the highest revenue;
- "laying the largest total premium egg" metaphorically means the channel with the highest total premium;
- The metaphor of a golden goose and egg represents high profitability and success.

sql:
SELECT * 
FROM policyholders 
WHERE marital_status = 'married';

SELECT policyholder_id, gender, income
FROM policyholders
WHERE policyholder_id > 0;

SELECT policyholder_id
FROM policyholders
WHERE income > (SELECT AVG(income) FROM policyholders);

SELECT COUNT(DISTINCT policyholder_id) AS policyholder_count
FROM policies
WHERE monthly_premium_auto > (SELECT AVG(monthly_premium_auto) FROM policies);
